from prometheus_client import start_http_server, Gauge
import time
import os

# Define Gauge Metrics
DB_USERNAME = Gauge('db_username', 'Database Username', ['username'])
DB_PASSWORD = Gauge('db_password', 'Database Password', ['password'])
DB_HOST = Gauge('db_host', 'Database Host', ['host'])
DB_CONNECTION_STRING = Gauge('db_connection_string', 'Database Connection String', ['connection_string'])

def get_db_credentials():
    # Assuming the credentials are stored as environment variables
    username = os.getenv('DB_USERNAME')
    password = os.getenv('DB_PASSWORD')
    host = os.getenv('DB_HOST')
    connection_string = os.getenv('DB_CONNECTION_STRING')

    return username, password, host, connection_string

def process_request():
    username, password, host, connection_string = get_db_credentials()

    # Set the gauge metrics
    DB_USERNAME.labels(username=username).set(1)
    DB_PASSWORD.labels(password=password).set(1)
    DB_HOST.labels(host=host).set(1)
    DB_CONNECTION_STRING.labels(connection_string=connection_string).set(1)

if __name__ == '__main__':
    # Start up the server to expose the metrics.
    start_http_server(8000)
    while True:
        process_request()
        time.sleep(1)